// src/kernel/mod.rs\n\n#![no_std]\n\nuse kernel::prelude::*;\n\nmodule! {\n    name: b"my_kernel_module",\n    author: b"giorgosperak13",\n    description: b"A simple kernel module",\n    license: b"GPL",\n}\n\nstatic mut MY_MODULE: Option<KernelModule> = None;\n\nfn init_fn(module: &KernelModule) -> Result<(), kernel::ModuleError> {\n    pr_info!("Hello from the kernel module!\n");\n    unsafe {\n        MY_MODULE = Some(module.clone());\n    }\n    Ok(())\n}\n\nfn exit_fn() {\n    pr_info!("Goodbye from the kernel module!\n");\n}\n\nmodule_init!(init_fn);\nmodule_exit!(exit_fn);\n